# Authenticated Primevest API Tests (PowerShell)
# Usage: powershell -ExecutionPolicy Bypass -File test-api-auth.ps1

$baseUrl = "http://localhost:3000"
$token = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.'  # Cookie secret added
$headers = @{ 
  'Accept' = 'application/json'
  'Authorization' = "Bearer $token"
}

# Test authenticated endpoints
'Testing dashboard summary:'
iwr "$baseUrl/api/dashboard/summary" -Method Get -Headers $headers | % StatusCode, @{n='Response';e={($_.Content | ConvertFrom-Json | ConvertTo-Json -Depth 3)} }

'Testing support tickets GET:'
iwr "$baseUrl/api/support/tickets?page=1" -Method Get -Headers $headers | % StatusCode, @{n='Response';e={($_.Content | ConvertFrom-Json | ConvertTo-Json -Depth 3)} }

'Testing support ticket POST:'
$body = @{category='cli';subject='Auth Test';message='Success with token!'} | ConvertTo-Json
iwr "$baseUrl/api/support/tickets" -Method Post -Body $body -ContentType 'application/json' -Headers $headers | % StatusCode, @{n='Response';e={($_.Content | ConvertFrom-Json | ConvertTo-Json -Depth 3)} }

Write-Host '✅ Authenticated tests ready!' -ForegroundColor Green

